export function wrapStarsRatingLevel(level: number) {
  if(level < 0) {
    const icon = Icon('warning')
    icon.classList.add('stars-rating-icon', 'stars-rating-icon-warning')
    return icon
  }

  const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
  svg.setAttribute('width', '24');
  svg.setAttribute('height', '24');
  svg.setAttribute('viewBox', '0 0 72 72');

  const mask = document.createElementNS('http://www.w3.org/2000/svg', 'mask')
  const maskId = '' + Math.random()
  mask.setAttribute('id', maskId)
  mask.setAttribute('mask-type', 'luminance')

  const maskBg = document.createElementNS('http://www.w3.org/2000/svg', 'rect')
  maskBg.setAttribute('fill', '#000')
  maskBg.setAttribute('width', '100%')
  maskBg.setAttribute('height', '100%')
  mask.appendChild(maskBg)

  for(const [pathLvl, path] of LEVELS_PATHS) {
    if(pathLvl <= level) {
      const el = document.createElementNS('http://www.w3.org/2000/svg', 'path')
      el.setAttribute('d', path)
      el.setAttribute('fill-rule', 'evenodd')
      el.setAttribute('fill', '#fff')
      mask.appendChild(el)
      break
    }
  }

  const text = document.createElementNS('http://www.w3.org/2000/svg', 'text')
  text.setAttribute('fill', '#000')
  text.setAttribute('font-size', '27')
  text.setAttribute('font-weight', '700')
  text.setAttribute('text-anchor', 'middle')
  text.setAttribute('x', '50%')
  text.setAttribute('y', '46')
  text.textContent = level.toString()
  mask.appendChild(text)

  svg.appendChild(mask)

  const bg = document.createElementNS('http://www.w3.org/2000/svg', 'rect')
  bg.setAttribute('fill', 'currentColor')
  bg.setAttribute('width', '100%')
  bg.setAttribute('height', '100%')
  bg.setAttribute('mask', `url(#${maskId})`)
  svg.appendChild(bg)

  const div = document.createElement('div')
  div.classList.add('stars-rating-icon')
  div.appendChild(svg)

  return div
}
